// 名言扩充数据，按大师 ID 分组
// 字段: cn(中), en(英,可选), src(出处), year(可选), tags(标签简写)
// tag 简写: v/l/r/c/cc/m/md/lr/b/p

const data = {};

// ========== 巴菲特: 90 条 ==========
data["m-buffett"] = [
  { cn: "投资很简单，但并不容易。", en: "Investing is simple, but not easy.", src: "伯克希尔股东大会", tags: ["md"] },
  { cn: "现金对企业就像氧气对人：99%的时间你不会注意它，缺了那1%它就是一切。", en: "Cash is to a business as oxygen is to an individual.", src: "致股东的信", year: 2014, tags: ["r", "b"] },
  { cn: "最好的生意是那种长期内只需要少量资本就能不断赚取高额回报的。", en: "The best businesses produce ever-growing earnings with little need for additional capital.", src: "致股东的信", year: 2007, tags: ["b", "v"] },
  { cn: "护城河越宽越深，企业就越值得拥有。", en: "We want a business with a wide and long-lasting moat.", src: "致股东的信", year: 1999, tags: ["b"] },
  { cn: "我宁愿大致正确，也不要精确错误。", en: "It is better to be approximately right than precisely wrong.", src: "伯克希尔股东大会", tags: ["md", "v"] },
  { cn: "在投资中，悲观是你的朋友，亢奋是你的敌人。", en: "The most common cause of low prices is pessimism.", src: "致股东的信", year: 1990, tags: ["c", "md"] },
  { cn: "股票市场是把钱从没耐心的人转到有耐心的人那里的工具。", en: "The stock market transfers money from the impatient to the patient.", src: "访谈", tags: ["l", "md"] },
  { cn: "如果你不能控制自己的情绪，你就不能控制自己的钱。", en: "If you cannot control your emotions, you cannot control your money.", src: "访谈", tags: ["md"] },
  { cn: "买股票就是买公司的一部分所有权。", en: "When we buy stocks, we are buying pieces of businesses.", src: "致股东的信", year: 1996, tags: ["b", "v"] },
  { cn: "风险来自于你不知道自己在做什么。", en: "Risk comes from not knowing what you are doing.", src: "访谈", tags: ["r", "cc"] },
  { cn: "把鸡蛋放在你最熟悉的篮子里，然后看好它。", en: "Put your eggs in one basket and watch the basket.", src: "致股东的信", year: 1993, tags: ["cc", "r"] },
  { cn: "聪明的投资者会让市场为自己服务，而不是被市场牵着走。", en: "The market is there to serve you, not to instruct you.", src: "致股东的信", year: 1987, tags: ["m", "md"] },
  { cn: "复利是世界第八大奇迹，理解它的人能赚到它，不理解的人会付出它。", en: "Compound interest is a powerful force.", src: "访谈", tags: ["l"] },
  { cn: "我从没想过靠预测短期市场赚钱。", en: "Forecasters make fortune-tellers look good.", src: "致股东的信", year: 1992, tags: ["m"] },
  { cn: "选择你的伴侣比选择股票更重要。", en: "Marry the right person.", src: "演讲", tags: ["p"] },
  { cn: "习惯的枷锁，开始时轻得无法察觉，等到察觉时却已重得无法挣脱。", en: "Chains of habit are too light to be felt until they are too heavy to be broken.", src: "演讲", tags: ["p", "lr"] },
  { cn: "我跳着踢踏舞去上班。", en: "I tap-dance to work.", src: "访谈", tags: ["p"] },
  { cn: "投资那种即便是傻瓜也能经营好的生意，因为总有一天傻瓜真的会去经营它。", en: "Invest in businesses an idiot could run, because one day one will.", src: "访谈", tags: ["b"] },
  { cn: "在游泳池里跳水之前，先看看里面有没有水。", en: "Predicting rain doesn't count. Building arks does.", src: "致股东的信", year: 2001, tags: ["r"] },
  { cn: "用买杂货的方式买股票，而不是用买香水的方式买股票。", en: "Buy stocks like you buy groceries, not perfume.", src: "访谈", tags: ["v", "md"] },
  { cn: "成功的投资是平淡的，刺激的投资往往是亏钱的。", en: "Successful investing takes time, discipline and patience.", src: "致股东的信", year: 1990, tags: ["md", "l"] },
  { cn: "最好的投资就是投资自己。", en: "The most important investment you can make is in yourself.", src: "演讲", tags: ["lr", "p"] },
  { cn: "今天有人能坐在树荫下乘凉，是因为很久以前有人种下了树。", en: "Someone is sitting in the shade today because someone planted a tree long ago.", src: "致股东的信", year: 1991, tags: ["l", "p"] },
  { cn: "我们不需要比别人聪明，只需要比别人更有纪律。", en: "We don't have to be smarter than the rest. We have to be more disciplined.", src: "访谈", tags: ["md"] },
  { cn: "买入并持有一家伟大的公司，比试图猜测市场顶部要明智得多。", en: "Buy and hold great companies.", src: "致股东的信", year: 1988, tags: ["l", "b"] },
  { cn: "一家伟大企业最重要的特征是其难以被颠覆的竞争优势。", en: "The key to investing is determining the competitive advantage of any given company.", src: "财富杂志", year: 1999, tags: ["b"] },
  { cn: "我的工作是估值，而不是预测市场。", en: "I never attempt to make money on the stock market.", src: "致股东的信", year: 1988, tags: ["v", "b"] },
  { cn: "不要看股价，看企业。", en: "We don't look at stock prices. We look at businesses.", src: "伯克希尔股东大会", tags: ["b"] },
  { cn: "在别人为新闻头条而恐慌时，要把它当成机会。", en: "Look at market fluctuations as your friend rather than your enemy.", src: "致股东的信", year: 1997, tags: ["c", "m"] },
  { cn: "金钱不会让你变得更好，但它会显示你本来是什么样的人。", en: "Money won't change how healthy you are or how many people love you.", src: "演讲", tags: ["p"] },
  { cn: "诚信是雇人的第一条标准——没有它，能力越强越糟糕。", en: "Hire for integrity, intelligence and energy. If they don't have the first, the other two will kill you.", src: "演讲", tags: ["p", "b"] },
  { cn: "把自己想象成只有20个打孔位的卡片，每做一次投资就打一个孔。", en: "Punch your card very carefully if you only had twenty holes.", src: "演讲", tags: ["cc", "v"] },
  { cn: "如果你做了功课，你就用不着分散投资。", en: "Wide diversification is only required when investors do not understand what they are doing.", src: "致股东的信", year: 1993, tags: ["cc", "lr"] },
  { cn: "不要用自己输不起的钱去投资。", en: "Never risk what you have and need for what you don't have and don't need.", src: "访谈", tags: ["r"] },
  { cn: "好生意自己会替你说话，烂生意你怎么解释都没用。", en: "Energy devoted to changing vessels beats patching leaks.", src: "致股东的信", year: 1985, tags: ["b"] },
  { cn: "我宁愿要一个我能理解的不算精彩的生意，也不要一个我看不懂的所谓好生意。", en: "I'd rather have a fair business I understand than a great one I don't.", src: "伯克希尔股东大会", tags: ["cc", "b"] },
  { cn: "好公司是即使被普通经理人管理也能保持赚钱能力的公司。", en: "Bad reputations of businesses tend to remain intact.", src: "致股东的信", year: 1980, tags: ["b"] },
  { cn: "杠杆是聪明人破产的最常见方式。", en: "Smart people go broke from leverage.", src: "访谈", tags: ["r"] },
  { cn: "好公司+合理价格+长期持有=投资成功的全部秘诀。", en: "Buy great companies at fair prices and hold them.", src: "致股东的信", year: 1989, tags: ["v", "b", "l"] },
  { cn: "每天读500页书。这就是知识发挥作用的方式。", en: "Read 500 pages every day. That's how knowledge works.", src: "演讲", tags: ["lr"] },
  { cn: "金钱的真正价值，是它带给你的自由。", en: "Money is just a means to an end.", src: "演讲", tags: ["p"] },
  { cn: "投资就像找配偶——你只需要一两个真正合适的就够了。", en: "You only have to do a very few things right in your life.", src: "演讲", tags: ["v", "p"] },
  { cn: "不要把分析的精力浪费在不可知的事物上。", en: "Forecasts may tell you a great deal about the forecaster; nothing about the future.", src: "致股东的信", year: 1980, tags: ["m", "md"] },
  { cn: "长期看，市场是有效的；短期它会犯各种错误，这就是我们的机会。", en: "Markets are efficient long-term but inefficient short-term.", src: "致股东的信", year: 1988, tags: ["m", "v"] },
  { cn: "投资的核心是评估一家企业未来的现金流。", en: "Intrinsic value is the discounted value of cash that can be taken out of a business.", src: "致股东的信", year: 1992, tags: ["v", "b"] },
  { cn: "我们追求的不是大动作，而是长期不被打断的复利。", en: "Compound interest is wondrous if uninterrupted.", src: "演讲", tags: ["l"] },
  { cn: "你必须为你不知道的事情留有余地——这就是安全边际。", en: "Margin of safety is the cornerstone of investment success.", src: "致股东的信", year: 1992, tags: ["v", "r"] },
  { cn: "投资中最大的敌人是费用、税收和情绪。", en: "Costs, taxes and emotions are the enemies of returns.", src: "致股东的信", year: 1996, tags: ["md", "r"] },
  { cn: "我们不喜欢戏剧性的转变；我们喜欢可预测的伟大企业。", en: "Turnarounds seldom turn.", src: "致股东的信", year: 1979, tags: ["b"] },
  { cn: "聪明地投资就是有纪律地投资。", en: "Investing intelligently means investing with discipline.", src: "演讲", tags: ["md"] },
  { cn: "投资的圣杯是稳定可预测的盈利能力。", en: "We look for predictable, durable earnings power.", src: "致股东的信", year: 1996, tags: ["b", "v"] },
  { cn: "我从不试图跨越七尺高的栏杆，我只寻找一尺高、可以轻松跨过的栏杆。", en: "I look for one-foot bars to step over, not seven-foot bars.", src: "演讲", tags: ["cc", "v"] },
  { cn: "学会等待是投资中最难的功课之一。", en: "The market transfers money from the active to the patient.", src: "致股东的信", year: 1989, tags: ["md", "l"] },
  { cn: "投资成功不需要超人的智商，只需要稳定的情绪。", en: "Success doesn't correlate with IQ once you're above 25.", src: "演讲", tags: ["md"] },
  { cn: "用25%的精力研究公司，用75%的精力管理自己的情绪。", en: "Investing is more about controlling yourself than markets.", src: "访谈", tags: ["md", "lr"] },
  { cn: "好生意的标志是定价权——能不断提价而不流失客户。", en: "The single most important decision in evaluating a business is pricing power.", src: "访谈", tags: ["b"] },
  { cn: "我从不出售一家我喜欢的公司，除非它的基本面发生了改变。", en: "Lethargy bordering on sloth is the cornerstone of our investment style.", src: "致股东的信", year: 1990, tags: ["l", "b"] },
  { cn: "永远不要追逐热门股票。", en: "Don't chase hot stocks; chase enduring businesses.", src: "致股东的信", year: 2000, tags: ["c", "v"] },
  { cn: "市场每年总会给你几次完美的击球机会，你要做的就是耐心等待。", en: "Wait for the fat pitch.", src: "演讲", tags: ["md", "l"] },
  { cn: "投资是为了在不确定中实现确定的回报。", en: "We pay up for certainty.", src: "致股东的信", year: 1993, tags: ["v", "r"] },
  { cn: "学习的最佳方式是研究他人的失败，而不是他人的成功。", en: "Study failure to avoid it.", src: "演讲", tags: ["lr", "c"] },
  { cn: "短期市场预测是毒药。", en: "Short-term market forecasts are poison.", src: "致股东的信", year: 1992, tags: ["m"] },
  { cn: "你不需要打破老规则去赚钱；只要遵守老规则就够了。", en: "There's nothing new in investing—only forgotten lessons.", src: "演讲", tags: ["lr", "v"] },
  { cn: "投资就是把今天的钱播下去，期待将来收获更多的钱。", en: "Investing is laying out money now to get more in the future.", src: "佛罗里达大学演讲", year: 1998, tags: ["v", "l"] },
  { cn: "如果一家公司必须靠会计花招来粉饰业绩，远离它。", en: "If management is willing to mislead investors, what won't they do?", src: "致股东的信", year: 2002, tags: ["b", "r"] },
  { cn: "管理层的诚信比智慧更重要。", en: "Honesty is the first chapter of wisdom.", src: "演讲", tags: ["b", "p"] },
  { cn: "我不投资我不喜欢的人。", en: "Life is too short to do business with people you don't like.", src: "演讲", tags: ["p", "b"] },
  { cn: "一个好的决策可能在十年里都看不到回报，要有耐心。", en: "Time is the friend of the wonderful business.", src: "致股东的信", year: 1989, tags: ["l", "b"] },
  { cn: "我的成功并非源于聪明，而是源于克服愚蠢。", en: "Avoiding stupidity is easier than seeking brilliance.", src: "演讲", tags: ["lr", "md"] },
  { cn: "用最坏情况的结果来决定仓位。", en: "Plan for the worst, hope for the best.", src: "致股东的信", year: 2000, tags: ["r"] },
  { cn: "永远不要忘记两件事：你会犯错，市场也会。", en: "You will make mistakes; so will the market.", src: "致股东的信", year: 1987, tags: ["m", "md"] },
  { cn: "宁愿让现金躺着发霉，也不愿做出愚蠢的投资。", en: "We would rather hold cash than make a stupid investment.", src: "致股东的信", year: 1998, tags: ["r", "md"] },
  { cn: "我不相信能够准确预测宏观经济的人。", en: "Macroeconomic forecasters are rarely right.", src: "致股东的信", year: 1992, tags: ["m"] },
  { cn: "投资中的运气是真实存在的，但不能依赖。", en: "Luck is when preparation meets opportunity.", src: "演讲", tags: ["md", "p"] },
  { cn: "把自己当作公司的合伙人，而不是股票的持有者。", en: "We are partners, not punters.", src: "致股东的信", year: 1996, tags: ["b", "l"] },
  { cn: "永远不要为别人的恐慌买单。", en: "Bad news is an investor's best friend.", src: "致股东的信", year: 2008, tags: ["c", "md"] },
  { cn: "我不在乎股价短期下跌——它只是给我便宜买入的机会。", en: "When stocks go down, you get more for your money.", src: "访谈", tags: ["v", "c"] },
  { cn: "在投资中，正确的判断+错误的时机=亏钱。", en: "Being right too soon is the same as being wrong.", src: "演讲", tags: ["m", "md"] },
  { cn: "成功的投资者要有内在的评分卡。", en: "The big question is whether you have an Inner Scorecard or an Outer Scorecard.", src: "演讲", tags: ["md", "p"] },
  { cn: "选择行业比选择股票更重要。", en: "Choose your industry first, then your company.", src: "访谈", tags: ["b", "v"] },
  { cn: "成功来自于把简单的事重复做。", en: "Investing is simple but not easy.", src: "演讲", tags: ["lr", "md"] },
  { cn: "我不害怕熊市，我害怕的是为牛市付出过高代价。", en: "Bear markets make people money; they just don't know it at the time.", src: "致股东的信", year: 1990, tags: ["c", "m"] },
  { cn: "在投资中，简单胜过复杂。", en: "Beware of geeks bearing formulas.", src: "致股东的信", year: 2008, tags: ["md", "lr"] },
  { cn: "好的合伙人胜过任何投资策略。", en: "Hang out with people better than you.", src: "演讲", tags: ["p"] },
  { cn: "我学到的最重要一课，是承认自己的局限。", en: "Know the edge of your competence.", src: "演讲", tags: ["cc", "lr"] },
  { cn: "想要变得富有，不在于你赚多少，而在于你保住多少。", en: "It's not how much you make, but how much you keep.", src: "演讲", tags: ["r", "p"] },
  { cn: "永远不要嘲笑节俭的人。", en: "Frugality is an underrated virtue.", src: "演讲", tags: ["p"] },
  { cn: "把投资视为一辈子的事，而不是一次买卖。", en: "Investing is a lifelong process.", src: "致股东的信", year: 1996, tags: ["l", "lr"] },
  { cn: "我宁愿持有几只伟大的股票，而不是一篮子平庸的股票。", en: "Concentration in great businesses beats diversification in mediocre ones.", src: "演讲", tags: ["cc", "b"] },
  { cn: "如果一笔交易需要复杂模型才能说服自己，多半是错的。", en: "If you need a computer to figure out you should buy it, you shouldn't.", src: "演讲", tags: ["md", "v"] },
  { cn: "对于个人投资者，最大的优势就是可以耐心等待。", en: "The individual investor's greatest edge is patience.", src: "致股东的信", year: 1996, tags: ["md", "l"] },
  { cn: "我们的目标不是预测未来，而是为各种未来做好准备。", en: "We don't predict; we prepare.", src: "致股东的信", year: 2008, tags: ["r", "md"] },
];

// ========== 芒格: 30 条 ==========
data["m-munger"] = [
  { cn: "学会理性地接受坏消息——延迟它对你毫无帮助。", en: "Face reality even when you don't like it.", src: "Daily Journal 股东大会", tags: ["md", "lr"] },
  { cn: "嫉妒是七宗罪中唯一让人毫无乐趣的。", en: "Envy is the only deadly sin that's no fun at all.", src: "穷查理宝典", tags: ["p"] },
  { cn: "如果你能始终保持客观、避免愚蠢，你会比绝大多数聪明人都成功。", en: "It's remarkable how much advantage comes from trying to be consistently not stupid.", src: "演讲", tags: ["md", "lr"] },
  { cn: "做一个负责任的人，比做一个聪明的人更难。", en: "Take a simple idea and take it seriously.", src: "演讲", tags: ["p", "md"] },
  { cn: "在生意中，你不需要每年都赢，你只需要不输大就行。", en: "Avoid catastrophic failures more than chasing wins.", src: "穷查理宝典", tags: ["r"] },
  { cn: "如果你想得到一样东西，就要让自己配得上它。", en: "The best way to get what you want is to deserve what you want.", src: "南加州大学法学院演讲", year: 2007, tags: ["p", "lr"] },
  { cn: "正确的关键决策少之又少——但正是它们决定了你的一生。", en: "A few major decisions, made well, dominate life's outcomes.", src: "演讲", tags: ["md"] },
  { cn: "最好的投资机会通常在你能力圈的边缘，而非中心。", en: "Real opportunities live at the edge of your competence.", src: "Daily Journal 股东大会", tags: ["cc"] },
  { cn: "复利是世界第八大奇迹——千万不要无谓地打断它。", en: "First rule of compounding: never interrupt it unnecessarily.", src: "演讲", tags: ["l"] },
  { cn: "理解激励机制就理解了人类行为的大部分。", en: "Show me the incentives and I'll show you the outcome.", src: "穷查理宝典", tags: ["b", "p"] },
  { cn: "聪明人犯傻，往往是因为他们试图一夜暴富。", en: "Smart people get into trouble looking for easy money.", src: "Daily Journal 股东大会", tags: ["r", "md"] },
  { cn: "投资的真理简单到让人难以接受。", en: "Investment truths are simple but hard to accept.", src: "演讲", tags: ["lr"] },
  { cn: "永远不要为预测付费，要为正确的判断付费。", en: "Pay for judgment, not forecasts.", src: "演讲", tags: ["m", "md"] },
  { cn: "成功的投资就像逆向工程——你要先想清楚什么会失败。", en: "Invert, always invert.", src: "演讲", tags: ["c", "lr"] },
  { cn: "保持谦卑，因为市场总会给傲慢的人上一课。", en: "The market is humbling for the arrogant.", src: "Daily Journal 股东大会", tags: ["md", "m"] },
  { cn: "不要试图比别人聪明，而要试图比别人少犯傻。", en: "Try to be less stupid, not smarter.", src: "演讲", tags: ["md", "lr"] },
  { cn: "想要长寿，就把自己置于不会被杀的位置。", en: "Long-term advantage comes from avoiding catastrophe.", src: "演讲", tags: ["r", "p"] },
  { cn: "拥有多元思维模型的人能看到别人看不到的机会。", en: "You've got to have models in your head.", src: "穷查理宝典", tags: ["lr"] },
  { cn: "你必须读得多、想得多、活得长。", en: "Read a lot. Think a lot. Live long.", src: "演讲", tags: ["lr", "p"] },
  { cn: "如果一件事很难，那就走简单路；如果简单路也难，那就放下。", en: "If something is too hard, we move on.", src: "Daily Journal 股东大会", tags: ["cc", "md"] },
  { cn: "想清楚再行动，比快速行动更重要。", en: "Direction matters more than speed.", src: "演讲", tags: ["md"] },
  { cn: "把别人的失败当作免费的教科书。", en: "Other people's mistakes are the cheapest tuition.", src: "演讲", tags: ["lr", "c"] },
  { cn: "拥有伟大企业，胜过频繁交易。", en: "The big money is not in the buying and selling, but in the waiting.", src: "演讲", tags: ["l", "b"] },
  { cn: "一旦理解了复利，你就理解了财富。", en: "Understanding compound interest is the secret to wealth.", src: "演讲", tags: ["l"] },
  { cn: "拒绝那些诱人但你不理解的机会，是终身的纪律。", en: "Discipline is saying no to attractive things you don't understand.", src: "Daily Journal 股东大会", tags: ["cc", "md"] },
  { cn: "把生活和工作中的愚蠢都剔除——这本身就是巨大的优势。", en: "Eliminating stupidity is more important than seeking brilliance.", src: "演讲", tags: ["lr", "md"] },
  { cn: "在重要的事情上，不能凑合。", en: "On important decisions, don't settle.", src: "演讲", tags: ["md", "p"] },
  { cn: "我从未见过聪明而又懒散的人能取得长久成功。", en: "I've never seen anyone succeed long-term who was both smart and lazy.", src: "演讲", tags: ["lr", "p"] },
  { cn: "如果你被恐惧或贪婪驱使，你就不该做投资。", en: "Fear and greed disqualify you from rational investing.", src: "演讲", tags: ["md"] },
  { cn: "成功的关键是把简单的真理坚持50年。", en: "Persistence on simple truths over decades is the secret.", src: "演讲", tags: ["l", "md"] },
];

// ========== 格雷厄姆: 30 条 ==========
data["m-graham"] = [
  { cn: "投资业务最好按商业的方式来运作。", en: "Investment is most intelligent when it is most businesslike.", src: "聪明的投资者", year: 1949, tags: ["b", "v"] },
  { cn: "防御型投资者的目标是避免严重错误，并获得令人满意的回报。", en: "The defensive investor's primary aim is to avoid serious mistakes.", src: "聪明的投资者", year: 1949, tags: ["r", "v"] },
  { cn: "进攻型投资者要愿意付出比常人更多的努力。", en: "The enterprising investor must devote substantial effort.", src: "聪明的投资者", year: 1949, tags: ["lr"] },
  { cn: "不要把投资和投机混为一谈。", en: "An investment operation promises safety of principal and adequate return.", src: "证券分析", year: 1934, tags: ["v", "r"] },
  { cn: "市场先生每天都来报价，你可以接受也可以忽略。", en: "Mr. Market is your servant, not your guide.", src: "聪明的投资者", year: 1949, tags: ["m", "md"] },
  { cn: "买股票就是买公司的一部分，永远要这么想。", en: "A stock is a piece of a business.", src: "聪明的投资者", year: 1949, tags: ["b"] },
  { cn: "智慧的投资者卖给乐观主义者，从悲观主义者手中买入。", en: "The intelligent investor sells to optimists and buys from pessimists.", src: "聪明的投资者", year: 1949, tags: ["c", "md"] },
  { cn: "几乎所有的牛市都有共同特征——以及随后的崩溃。", en: "Bull markets follow familiar patterns with familiar consequences.", src: "聪明的投资者", year: 1949, tags: ["m"] },
  { cn: "投资者赔钱的主要原因是因为他们的情绪被激起了。", en: "The investor's chief problem is likely to be himself.", src: "聪明的投资者", year: 1949, tags: ["md"] },
  { cn: "对绝大多数投资者来说，定期定额买入指数是最理性的策略。", en: "Dollar-cost averaging into indexes is the most rational strategy for most.", src: "聪明的投资者", year: 1949, tags: ["v", "l"] },
  { cn: "你能赚多少，主要取决于你的脾气，而不是你的智力。", en: "Investment success depends on temperament more than intellect.", src: "聪明的投资者", year: 1949, tags: ["md"] },
  { cn: "波动并不等于风险——错误的判断才是。", en: "Volatility is not risk; permanent loss of capital is.", src: "证券分析", year: 1934, tags: ["r", "m"] },
  { cn: "在牛市中犯错的代价，要在熊市才会显现。", en: "The bills come due in bear markets.", src: "聪明的投资者", year: 1949, tags: ["m", "r"] },
  { cn: "懂得定价权的人，才懂得真正的护城河。", en: "Pricing power is the truest measure of competitive advantage.", src: "证券分析", year: 1934, tags: ["b"] },
  { cn: "盈利的可持续性比当期盈利更重要。", en: "Sustainability of earnings matters more than current earnings.", src: "证券分析", year: 1934, tags: ["b", "v"] },
  { cn: "用净资产折扣买公司，是格雷厄姆经典策略。", en: "Buying below net asset value provides a margin of safety.", src: "证券分析", year: 1934, tags: ["v", "r"] },
  { cn: "市场短期的疯狂，往往是长期的机会。", en: "Short-term insanity creates long-term opportunities.", src: "聪明的投资者", year: 1949, tags: ["c", "m"] },
  { cn: "聪明的投资者既不情绪化也不被情绪牵引。", en: "The intelligent investor is unemotional yet not detached.", src: "聪明的投资者", year: 1949, tags: ["md"] },
  { cn: "杠杆放大了你的判断错误，而不是你的智慧。", en: "Leverage magnifies mistakes, not wisdom.", src: "聪明的投资者", year: 1949, tags: ["r"] },
  { cn: "宁可做对而无聊，也不要刺激而错误。", en: "Boring and right beats exciting and wrong.", src: "聪明的投资者", year: 1949, tags: ["md", "v"] },
  { cn: "财务报表是投资者的圣经，而不是新闻。", en: "Financial statements drive decisions, not headlines.", src: "证券分析", year: 1934, tags: ["b", "lr"] },
  { cn: "买便宜要分散，买伟大可以集中。", en: "Diversify when buying cheap; concentrate when buying great.", src: "证券分析", year: 1934, tags: ["v", "r"] },
  { cn: "在估值上保守，就是在风险上激进。", en: "Conservative valuation is aggressive risk control.", src: "聪明的投资者", year: 1949, tags: ["v", "r"] },
  { cn: "市场永远在两种情绪之间摇摆：贪婪与恐惧。", en: "The market swings between greed and fear, never reason.", src: "聪明的投资者", year: 1949, tags: ["m", "md"] },
  { cn: "对内在价值的估算可以模糊，但必须有底线。", en: "Intrinsic value can be approximate, but it must be bounded.", src: "证券分析", year: 1934, tags: ["v"] },
  { cn: "防御型投资的核心是规则，而不是预测。", en: "Defensive investing relies on rules, not forecasts.", src: "聪明的投资者", year: 1949, tags: ["v", "md"] },
  { cn: "永远要假设：市场可能比你预想的更不理性，更久。", en: "Markets can stay irrational longer than you can stay solvent.", src: "聪明的投资者", year: 1949, tags: ["m", "r"] },
  { cn: "投资者最大的敌人在镜子里。", en: "The investor's worst enemy is the one in the mirror.", src: "聪明的投资者", year: 1949, tags: ["md"] },
  { cn: "如果你不能在市场下跌50%时保持冷静，就不该买股票。", en: "If you can't watch a 50% decline calmly, you shouldn't be in stocks.", src: "聪明的投资者", year: 1949, tags: ["md", "r"] },
  { cn: "估值不是一个点，而是一个区间。", en: "Valuation is a range, not a point.", src: "证券分析", year: 1934, tags: ["v"] },
];

// ========== 林奇: 30 条 ==========
data["m-lynch"] = [
  { cn: "周末花的时间研究股票，比看股价的时间更有价值。", en: "More time on research, less on tickers.", src: "彼得·林奇的成功投资", year: 1989, tags: ["lr"] },
  { cn: "股价短期波动是噪声，长期是真相。", en: "Price movements short-term are noise; long-term they tell the truth.", src: "战胜华尔街", year: 1993, tags: ["m", "l"] },
  { cn: "我喜欢那些名字无聊、业务无聊但赚钱不无聊的公司。", en: "Boring names, boring business, exciting earnings.", src: "彼得·林奇的成功投资", year: 1989, tags: ["b", "c"] },
  { cn: "如果连一个孩子都不能解释你买股票的理由，那就别买。", en: "If you can't explain it to a child, don't own it.", src: "彼得·林奇的成功投资", year: 1989, tags: ["cc"] },
  { cn: "好公司的好股票，往往出现在被忽视的角落。", en: "Great stocks often hide in unfashionable corners.", src: "战胜华尔街", year: 1993, tags: ["c", "v"] },
  { cn: "投资十倍股的关键是：买入并坚持持有。", en: "The trick to tenbaggers is not selling them too soon.", src: "彼得·林奇的成功投资", year: 1989, tags: ["l", "b"] },
  { cn: "我从不在自己看不懂的故事上下注。", en: "Know what you own.", src: "彼得·林奇的成功投资", year: 1989, tags: ["cc", "b"] },
  { cn: "市场预测是为了让占星术看起来更可靠。", en: "Nobody can predict interest rates or markets.", src: "战胜华尔街", year: 1993, tags: ["m"] },
  { cn: "永远不要在自己不熟悉的领域放大杠杆。", en: "Never invest in any idea you can't illustrate with a crayon.", src: "彼得·林奇的成功投资", year: 1989, tags: ["cc", "r"] },
  { cn: "好故事+好财务+合理估值=好股票。", en: "Story + numbers + price = winner.", src: "战胜华尔街", year: 1993, tags: ["v", "b"] },
  { cn: "我每年研究上千只股票，最后下注的也就几十只。", en: "I look at hundreds of companies and buy only a few.", src: "彼得·林奇的成功投资", year: 1989, tags: ["lr", "cc"] },
  { cn: "卖股票的理由必须比买入时更扎实。", en: "Selling requires more conviction than buying.", src: "战胜华尔街", year: 1993, tags: ["md"] },
  { cn: "我从超市的购物车里学到的，比从华尔街的研报里学到的多。", en: "I do my best research at the mall.", src: "彼得·林奇的成功投资", year: 1989, tags: ["lr", "b"] },
  { cn: "公司业绩长期决定股价，短期都是噪音。", en: "Earnings drive stock prices in the long run.", src: "战胜华尔街", year: 1993, tags: ["b", "l"] },
  { cn: "如果你对经济学家的预测充满信心，那你比他们更乐观。", en: "Forget about economists; study companies.", src: "彼得·林奇的成功投资", year: 1989, tags: ["m"] },
  { cn: "牛市来时不要兴奋，熊市来时不要绝望。", en: "Don't get euphoric in bull markets or despondent in bear markets.", src: "战胜华尔街", year: 1993, tags: ["md", "m"] },
  { cn: "想成为出色的投资者？读年报，读年报，再读年报。", en: "Read the annual report, then read it again.", src: "彼得·林奇的成功投资", year: 1989, tags: ["lr", "b"] },
  { cn: "在调整中买入是赚钱的，但只买你真正想拥有的公司。", en: "Buy in corrections, but only what you'd own anyway.", src: "战胜华尔街", year: 1993, tags: ["c", "v"] },
  { cn: "成长股的关键是寻找未来还能继续增长的公司。", en: "Growth investing is about future earnings power.", src: "彼得·林奇的成功投资", year: 1989, tags: ["b"] },
  { cn: "周期股的关键是把握周期顶部和底部。", en: "Timing matters most for cyclical stocks.", src: "彼得·林奇的成功投资", year: 1989, tags: ["m", "b"] },
  { cn: "再差的时机，对一家伟大的公司来说也只是小波折。", en: "For a great company, bad timing is a temporary inconvenience.", src: "战胜华尔街", year: 1993, tags: ["l", "b"] },
  { cn: "对我来说，最重要的指标是：这个公司明天还会存在吗？", en: "Will this company still be here in 10 years?", src: "战胜华尔街", year: 1993, tags: ["b", "l"] },
  { cn: "学会从生活中发现投资机会。", en: "Invest in what you see, hear, and use.", src: "彼得·林奇的成功投资", year: 1989, tags: ["lr", "cc"] },
  { cn: "投资中最大的危险是不学习。", en: "The biggest risk is not learning.", src: "战胜华尔街", year: 1993, tags: ["lr"] },
  { cn: "宁愿错过几只股票，也不要重仓你不懂的股票。", en: "Better to miss a winner than to lose on something you don't understand.", src: "彼得·林奇的成功投资", year: 1989, tags: ["cc", "r"] },
  { cn: "市场不会等任何人，但好公司会。", en: "Markets don't wait, but great companies reward those who do.", src: "战胜华尔街", year: 1993, tags: ["l", "b"] },
  { cn: "把目光放在未来三年，而不是下个季度。", en: "Look three years out, not three months.", src: "彼得·林奇的成功投资", year: 1989, tags: ["l"] },
  { cn: "不要因为股票涨了就卖，要因为公司变差了才卖。", en: "Don't sell because the price rose; sell when fundamentals deteriorate.", src: "战胜华尔街", year: 1993, tags: ["b", "md"] },
  { cn: "好的投资组合不是分散的同义词，而是优秀公司的集合。", en: "A good portfolio is a collection of great businesses.", src: "彼得·林奇的成功投资", year: 1989, tags: ["b", "cc"] },
  { cn: "关注利润率的变化，那是真正的早期信号。", en: "Profit margin trends are early warning signals.", src: "战胜华尔街", year: 1993, tags: ["b"] },
];

// ========== 索罗斯: 30 条 ==========
data["m-soros"] = [
  { cn: "市场不是反映现实的镜子，而是参与塑造现实的力量。", en: "Markets shape reality, not just reflect it.", src: "金融炼金术", year: 1987, tags: ["m", "p"] },
  { cn: "我的投资框架不是模型，而是不断检验的假设。", en: "My approach is hypothesis-driven, not model-driven.", src: "索罗斯谈索罗斯", year: 1995, tags: ["lr"] },
  { cn: "趋势改变的时刻，往往蕴含最大利润。", en: "Inflection points produce the biggest profits.", src: "金融炼金术", year: 1987, tags: ["m", "c"] },
  { cn: "宏观投资的本质是识别错误的共识。", en: "Macro investing is about spotting flawed consensus.", src: "索罗斯谈索罗斯", year: 1995, tags: ["c", "m"] },
  { cn: "在不确定中行动，比在确定中等待更有价值。", en: "Acting under uncertainty is more valuable than waiting for certainty.", src: "金融炼金术", year: 1987, tags: ["md", "r"] },
  { cn: "做错了不可怕，可怕的是不愿意止损。", en: "Cutting losses is the discipline of survival.", src: "访谈", tags: ["r", "md"] },
  { cn: "我每天都在准备承认自己的错误。", en: "I prepare to be wrong every day.", src: "访谈", tags: ["md", "lr"] },
  { cn: "金融市场是人性最赤裸的实验室。", en: "Markets are the most honest laboratory of human behavior.", src: "金融炼金术", year: 1987, tags: ["p", "m"] },
  { cn: "在泡沫顶部，所有人都很有道理，这才是危险所在。", en: "At market tops, everyone makes sense; that's the danger.", src: "金融市场新范式", year: 2008, tags: ["m", "c"] },
  { cn: "认知偏差是市场永远的朋友——也是永远的敌人。", en: "Cognitive bias is the market's eternal companion.", src: "索罗斯谈索罗斯", year: 1995, tags: ["md", "m"] },
  { cn: "在我看来，所有市场都是错的，问题只是错多少。", en: "Markets are always wrong; the question is how wrong.", src: "金融炼金术", year: 1987, tags: ["m"] },
  { cn: "投资中最大的优势是认知上的不对称。", en: "The biggest edge is asymmetric understanding.", src: "索罗斯谈索罗斯", year: 1995, tags: ["lr"] },
  { cn: "反身性理论提醒我们：观察者改变了被观察的对象。", en: "Reflexivity: the observer changes what is observed.", src: "金融炼金术", year: 1987, tags: ["p"] },
  { cn: "不要以为价格反映了所有信息，价格本身就是信息的扭曲。", en: "Prices don't reflect information; they distort it.", src: "金融市场新范式", year: 2008, tags: ["m"] },
  { cn: "我从来不害怕错，只害怕不能及时改错。", en: "I'm not afraid to be wrong; I'm afraid not to fix it.", src: "访谈", tags: ["md"] },
  { cn: "宏观判断要大胆，仓位管理要谨慎。", en: "Bold macro thesis, careful position sizing.", src: "索罗斯谈索罗斯", year: 1995, tags: ["r", "md"] },
  { cn: "认错是投资中最有利可图的习惯。", en: "Admitting mistakes is the most profitable habit.", src: "访谈", tags: ["md", "lr"] },
  { cn: "等待机会比寻找机会更重要。", en: "Waiting is more important than searching.", src: "索罗斯谈索罗斯", year: 1995, tags: ["md", "l"] },
  { cn: "重大利润来自于在共识破裂前下注。", en: "Big money is made by betting before the consensus breaks.", src: "金融市场新范式", year: 2008, tags: ["c", "m"] },
  { cn: "在泡沫中赚钱不是预测顶部，而是建立退出纪律。", en: "Don't predict the top; build an exit discipline.", src: "金融市场新范式", year: 2008, tags: ["r", "md"] },
  { cn: "市场永远在『正在发生的故事』中过度反应。", en: "Markets always overreact to unfolding narratives.", src: "金融炼金术", year: 1987, tags: ["m", "md"] },
  { cn: "我不投资我没有研究透的国家或资产。", en: "I don't invest in countries I haven't studied.", src: "访谈", tags: ["cc", "lr"] },
  { cn: "做空需要的不是勇气，而是耐心。", en: "Shorting requires patience, not courage.", src: "索罗斯谈索罗斯", year: 1995, tags: ["c", "md"] },
  { cn: "宏观大势会推翻所有微观正确性。", en: "Macro trumps micro in extreme times.", src: "金融市场新范式", year: 2008, tags: ["m"] },
  { cn: "我宁愿在不确定中正确，也不要在确定中平庸。", en: "I'd rather be right with uncertainty than mediocre with confidence.", src: "访谈", tags: ["c", "md"] },
  { cn: "投机是认知优势的兑现。", en: "Speculation is the cashing-in of insight.", src: "金融炼金术", year: 1987, tags: ["m"] },
  { cn: "金融历史的每一轮危机，都重复着相似的剧本。", en: "Every crisis has a familiar script.", src: "金融市场新范式", year: 2008, tags: ["m", "lr"] },
  { cn: "成功的投资者总是把『可能性』看得比『确定性』更重要。", en: "Probability matters more than certainty.", src: "索罗斯谈索罗斯", year: 1995, tags: ["md", "r"] },
  { cn: "保持怀疑——尤其是对你最相信的判断。", en: "Stay skeptical, especially about your strongest convictions.", src: "金融炼金术", year: 1987, tags: ["md", "lr"] },
  { cn: "不要恋战——市场不会奖励固执。", en: "Don't fall in love with positions; markets don't reward stubbornness.", src: "访谈", tags: ["md", "r"] },
];

// ========== 达利欧: 30 条 ==========
data["m-dalio"] = [
  { cn: "做你最害怕做的事，往往就是最值得做的事。", en: "Do what you fear; that's where growth lives.", src: "原则", year: 2017, tags: ["p", "lr"] },
  { cn: "把每一次失败当作一次升级。", en: "Treat every failure as an upgrade.", src: "原则", year: 2017, tags: ["lr", "md"] },
  { cn: "拥抱现实，处理现实，而不是抗拒现实。", en: "Embrace reality and deal with it.", src: "原则", year: 2017, tags: ["md", "p"] },
  { cn: "明白自己的弱点比知道自己的优势更重要。", en: "Knowing your weaknesses matters more than your strengths.", src: "原则", year: 2017, tags: ["cc", "lr"] },
  { cn: "不要让自尊心阻止你认错。", en: "Don't let your ego stop you from admitting mistakes.", src: "原则", year: 2017, tags: ["md"] },
  { cn: "桥水的成功是『极度透明』和『极度真实』的产物。", en: "Radical truth and radical transparency drive results.", src: "原则", year: 2017, tags: ["b", "p"] },
  { cn: "建立你自己的『决策机器』。", en: "Build your own decision-making machine.", src: "原则", year: 2017, tags: ["md", "lr"] },
  { cn: "全天候策略的核心是不被任何宏观情景击垮。", en: "All Weather is built to survive every regime.", src: "桥水投资备忘录", tags: ["r"] },
  { cn: "市场是一台债务驱动的机器。", en: "Markets are a debt-driven machine.", src: "原则", year: 2017, tags: ["m"] },
  { cn: "理解周期，比预测周期更重要。", en: "Understand cycles before predicting them.", src: "原则", year: 2017, tags: ["m", "lr"] },
  { cn: "找到你的两三个原则并坚持五十年。", en: "Find a few principles and stick with them for decades.", src: "原则", year: 2017, tags: ["l", "md"] },
  { cn: "我宁愿和提出尖锐反对意见的人合作。", en: "I value people who challenge me.", src: "原则", year: 2017, tags: ["lr", "p"] },
  { cn: "每一个决定都应该是一个被仔细思考过的赌注。", en: "Every decision is a bet.", src: "原则", year: 2017, tags: ["md", "r"] },
  { cn: "永远准备好承受最坏情况——这是生存的前提。", en: "Plan for the worst-case scenario.", src: "原则", year: 2017, tags: ["r"] },
  { cn: "情绪是大脑的杂音，纪律是清音。", en: "Emotion is noise, discipline is signal.", src: "原则", year: 2017, tags: ["md"] },
  { cn: "投资的本质是承担正确的、可承受的风险。", en: "Investing is taking the right, bearable risks.", src: "原则", year: 2017, tags: ["r"] },
  { cn: "聪明地犯错，比避免犯错更重要。", en: "Make smart mistakes, not careless ones.", src: "原则", year: 2017, tags: ["lr", "md"] },
  { cn: "和你不同意见的人坐下来辩论，是变聪明的捷径。", en: "Thoughtful disagreement is the fastest way to grow.", src: "原则", year: 2017, tags: ["lr"] },
  { cn: "去发现真相，比维持自尊更重要。", en: "Pursue truth over ego.", src: "原则", year: 2017, tags: ["md", "p"] },
  { cn: "不要带着错误的自信走完一生。", en: "Don't go through life with false confidence.", src: "原则", year: 2017, tags: ["md", "lr"] },
  { cn: "原则的价值在于，它在你最痛苦时仍然有效。", en: "Principles work when you need them most.", src: "原则", year: 2017, tags: ["md", "p"] },
  { cn: "决策的质量取决于你输入的信息质量。", en: "Decision quality depends on input quality.", src: "原则", year: 2017, tags: ["lr", "md"] },
  { cn: "把每一次危机当成一次系统升级的机会。", en: "Every crisis is an upgrade opportunity.", src: "原则", year: 2017, tags: ["c", "lr"] },
  { cn: "看清债务周期，你就看清了全球经济。", en: "Read the debt cycle and you read the world.", src: "债务危机", year: 2018, tags: ["m"] },
  { cn: "印钞解决不了价值问题，只能解决流动性问题。", en: "Printing money solves liquidity, not value.", src: "债务危机", year: 2018, tags: ["m"] },
  { cn: "在大周期的尾声，传统投资策略往往失效。", en: "Old playbooks fail at the end of long cycles.", src: "原则：应对变化中的世界秩序", year: 2021, tags: ["m"] },
  { cn: "宏观投资是把哲学变成头寸。", en: "Macro is philosophy turned into positions.", src: "原则", year: 2017, tags: ["m", "p"] },
  { cn: "永远要问：如果我错了会怎样？", en: "Always ask: what if I'm wrong?", src: "原则", year: 2017, tags: ["md", "r"] },
  { cn: "把『极度真诚』作为你和合作伙伴的契约。", en: "Make radical truth your contract.", src: "原则", year: 2017, tags: ["p"] },
  { cn: "进步=痛苦×反思。", en: "Progress = Pain × Reflection.", src: "原则", year: 2017, tags: ["lr", "p"] },
];

// ========== 马克斯: 30 条 ==========
data["m-marks"] = [
  { cn: "你只有在退潮时才知道谁在裸泳——但等到那时已经太晚。", en: "Only when the tide goes out do you discover who's been swimming naked.", src: "投资最重要的事", year: 2011, tags: ["r", "m"] },
  { cn: "周期会重复，但不会精确重复。", en: "Cycles rhyme; they don't repeat.", src: "周期", year: 2018, tags: ["m"] },
  { cn: "成功投资的关键，是在大多数人贪婪时保持谨慎。", en: "Be cautious when others are greedy.", src: "投资最重要的事", year: 2011, tags: ["c", "md"] },
  { cn: "你不能控制结果，但可以控制决策的质量。", en: "Control your decisions, not the outcomes.", src: "投资最重要的事", year: 2011, tags: ["md", "r"] },
  { cn: "投资中的『二阶思维』比一阶思维更重要。", en: "Second-level thinking matters more than first-level.", src: "投资最重要的事", year: 2011, tags: ["lr", "md"] },
  { cn: "买得便宜，是投资中最伟大的优势。", en: "Buying cheap is the greatest edge.", src: "投资最重要的事", year: 2011, tags: ["v"] },
  { cn: "不要被市场情绪牵着鼻子走。", en: "Don't be a slave to market sentiment.", src: "投资最重要的事", year: 2011, tags: ["md", "m"] },
  { cn: "对风险的真正定义不是波动，而是亏损的可能性。", en: "Risk is the probability of loss, not volatility.", src: "投资最重要的事", year: 2011, tags: ["r"] },
  { cn: "保护资本是投资的第一原则。", en: "Capital preservation comes first.", src: "投资最重要的事", year: 2011, tags: ["r"] },
  { cn: "我们的工作是寻找被错误定价的资产。", en: "Our job is to find mispriced assets.", src: "投资备忘录", tags: ["v"] },
  { cn: "在繁荣中保持警惕，在悲观中寻找机会。", en: "Be vigilant in booms, opportunistic in busts.", src: "投资最重要的事", year: 2011, tags: ["c", "m"] },
  { cn: "投资中没有什么是绝对正确的，只有大概率正确。", en: "Investing deals in probabilities, not certainties.", src: "投资最重要的事", year: 2011, tags: ["r", "md"] },
  { cn: "在错误的时间正确，仍然是错的。", en: "Being right too early is the same as being wrong.", src: "投资最重要的事", year: 2011, tags: ["md", "m"] },
  { cn: "不要做最聪明的人，做最不容易出错的人。", en: "Don't be the smartest; be the one who makes fewest mistakes.", src: "投资最重要的事", year: 2011, tags: ["md", "lr"] },
  { cn: "周期不是噪声，而是市场的本质。", en: "Cycles are not noise; they are the essence.", src: "周期", year: 2018, tags: ["m"] },
  { cn: "情绪就是周期的燃料。", en: "Emotions fuel cycles.", src: "周期", year: 2018, tags: ["md", "m"] },
  { cn: "好投资不是买好资产，而是买得好。", en: "Good investing isn't buying good things, it's buying things well.", src: "投资最重要的事", year: 2011, tags: ["v"] },
  { cn: "不要让对收益的渴望压过对风险的敬畏。", en: "Never let greed override risk awareness.", src: "投资最重要的事", year: 2011, tags: ["r", "md"] },
  { cn: "宏观预测对我们没用，价格对我们至关重要。", en: "Forecasts are useless; price matters most.", src: "投资备忘录", tags: ["v", "m"] },
  { cn: "投资就是为不确定的未来付出确定的代价。", en: "Investing is paying certain costs for uncertain futures.", src: "投资最重要的事", year: 2011, tags: ["r"] },
  { cn: "一笔好交易必须包含价格、价值与可能性的三重对齐。", en: "A great trade aligns price, value, and probability.", src: "投资备忘录", tags: ["v", "r"] },
  { cn: "如果一个想法太流行，它的回报多半已经透支。", en: "Popular ideas usually offer poor returns.", src: "投资最重要的事", year: 2011, tags: ["c"] },
  { cn: "在投资中，舒适感往往是危险信号。", en: "Comfort in investing is usually a warning.", src: "投资最重要的事", year: 2011, tags: ["c", "r"] },
  { cn: "不预测——准备。", en: "Don't predict—prepare.", src: "投资备忘录", tags: ["r", "md"] },
  { cn: "成功来自于在不被理解时坚持理性。", en: "Success comes from rational discipline against the crowd.", src: "投资最重要的事", year: 2011, tags: ["c", "md"] },
  { cn: "长期赚钱的方式是少犯大错。", en: "Long-term success means avoiding big errors.", src: "投资最重要的事", year: 2011, tags: ["r", "md"] },
  { cn: "市场效率被高估了。", en: "Market efficiency is overrated.", src: "投资最重要的事", year: 2011, tags: ["m"] },
  { cn: "没有便宜，就没有真正的安全边际。", en: "Without cheapness, there's no margin of safety.", src: "投资最重要的事", year: 2011, tags: ["v", "r"] },
  { cn: "周期顶部的乐观与底部的悲观，都是机会。", en: "Extreme optimism and extreme pessimism both signal opportunity.", src: "周期", year: 2018, tags: ["c", "m"] },
  { cn: "你不能让市场决定你的情绪。", en: "Don't let the market dictate your emotions.", src: "投资最重要的事", year: 2011, tags: ["md"] },
];

// ========== 博格: 30 条 ==========
data["m-bogle"] = [
  { cn: "费用是复利之敌。", en: "Costs are the enemy of compounding.", src: "共同基金常识", year: 1999, tags: ["l", "v"] },
  { cn: "投资者最重要的不是选择最好的基金，而是避开最差的基金。", en: "Avoiding the worst funds matters more than picking the best.", src: "共同基金常识", year: 1999, tags: ["r"] },
  { cn: "把指数基金当作底仓，是绝大多数家庭最好的选择。", en: "Index funds are the foundation for most families.", src: "共同基金常识", year: 1999, tags: ["v"] },
  { cn: "选股很难，跟随指数不难。", en: "Picking stocks is hard; owning the market isn't.", src: "共同基金常识", year: 1999, tags: ["v"] },
  { cn: "时间会奖励有耐心的投资者。", en: "Time rewards the patient.", src: "共同基金常识", year: 1999, tags: ["l"] },
  { cn: "市场总是会回归长期平均水平。", en: "Markets revert to the mean.", src: "共同基金常识", year: 1999, tags: ["m"] },
  { cn: "投资不该是兴奋的——它应该是无聊但有效的。", en: "Investing should be boring but effective.", src: "共同基金常识", year: 1999, tags: ["md", "l"] },
  { cn: "复杂的产品大多在保护销售者，而不是投资者。", en: "Complex products protect the seller, not the investor.", src: "共同基金常识", year: 1999, tags: ["r"] },
  { cn: "持有低成本的多元化组合，再加上时间，就是答案。", en: "Low cost + diversification + time = success.", src: "共同基金常识", year: 1999, tags: ["v", "l"] },
  { cn: "几十年前我相信的道理，今天依然成立：低成本、长期持有。", en: "Low cost and long-term still wins.", src: "演讲", tags: ["lr", "l"] },
  { cn: "短期内你可能因为运气而胜出，长期靠的是规则。", en: "Luck wins short-term; rules win long-term.", src: "共同基金常识", year: 1999, tags: ["md", "l"] },
  { cn: "市场不可预测，但你的成本可以由你掌控。", en: "Markets are uncertain; costs are not.", src: "共同基金常识", year: 1999, tags: ["v", "md"] },
  { cn: "频繁交易是财富的杀手。", en: "Frequent trading kills wealth.", src: "共同基金常识", year: 1999, tags: ["md", "l"] },
  { cn: "投资行业最大的悖论：付出越多，得到越少。", en: "In investing, you get what you don't pay for.", src: "共同基金常识", year: 1999, tags: ["v"] },
  { cn: "选择一只基金，不要看过去三年，要看费率与策略。", en: "Don't chase past performance; look at costs and strategy.", src: "共同基金常识", year: 1999, tags: ["v", "lr"] },
  { cn: "我从来不预测市场，我只设计可以承受任何市场的组合。", en: "I don't predict markets; I build resilient portfolios.", src: "演讲", tags: ["m", "r"] },
  { cn: "在大多数情况下，简单胜过复杂。", en: "Simplicity beats complexity.", src: "共同基金常识", year: 1999, tags: ["md"] },
  { cn: "投资是为了人生目标，而不是为了击败邻居。", en: "Invest for life goals, not bragging rights.", src: "演讲", tags: ["p"] },
  { cn: "我相信常识胜过华尔街。", en: "Common sense beats Wall Street.", src: "共同基金常识", year: 1999, tags: ["c", "lr"] },
  { cn: "对绝大多数投资者来说，主动管理是负和游戏。", en: "Active management is a negative-sum game for most investors.", src: "共同基金常识", year: 1999, tags: ["v"] },
  { cn: "公司治理决定了基金行业的良心。", en: "Governance determines the conscience of finance.", src: "演讲", tags: ["b", "p"] },
  { cn: "财富积累的秘密不是高回报，而是持续不断地复利。", en: "Wealth comes from sustained compounding.", src: "共同基金常识", year: 1999, tags: ["l"] },
  { cn: "不要为了短期表现而放弃长期纪律。", en: "Don't abandon long-term discipline for short-term performance.", src: "共同基金常识", year: 1999, tags: ["md", "l"] },
  { cn: "投资者最大的敌人是他自己的冲动。", en: "The investor's worst enemy is impulse.", src: "共同基金常识", year: 1999, tags: ["md"] },
  { cn: "把心思放在你能控制的事情上：成本、配置、行为。", en: "Focus on what you can control: cost, allocation, behavior.", src: "演讲", tags: ["md", "v"] },
  { cn: "对绝大多数人来说，宽基指数+定投+时间是最好的策略。", en: "Broad index + dollar cost average + time is unbeatable.", src: "共同基金常识", year: 1999, tags: ["v", "l"] },
  { cn: "选股的诱惑往往源于傲慢，而不是真正的优势。", en: "Stock-picking is often arrogance dressed as skill.", src: "演讲", tags: ["c", "md"] },
  { cn: "退休金的核心是稳健，不是激进。", en: "Retirement is about resilience, not aggression.", src: "演讲", tags: ["r"] },
  { cn: "金融行业的复杂性，往往是为了让你看不懂费用。", en: "Complexity in finance often hides costs.", src: "共同基金常识", year: 1999, tags: ["v"] },
  { cn: "投资中真正稀缺的，不是机会，而是耐心。", en: "Patience, not opportunity, is the rarest commodity.", src: "演讲", tags: ["md", "l"] },
];

// ========== 费雪: 30 条 ==========
data["m-fisher"] = [
  { cn: "好的成长股，是那种能持续多年高于平均增长率的公司。", en: "A growth stock can grow above average for many years.", src: "怎样选择成长股", year: 1958, tags: ["b", "l"] },
  { cn: "评估管理层的诚信和能力，是投资中最重要的功课。", en: "Assess management's integrity and competence.", src: "怎样选择成长股", year: 1958, tags: ["b"] },
  { cn: "通过『闲聊法』了解一家公司——和它的客户、供应商、员工聊天。", en: "Use the scuttlebutt method—talk to customers, suppliers, employees.", src: "怎样选择成长股", year: 1958, tags: ["lr", "b"] },
  { cn: "好公司的研发投入应该面向长期，而不是短期粉饰报表。", en: "R&D should serve the long term, not the next quarter.", src: "怎样选择成长股", year: 1958, tags: ["b", "l"] },
  { cn: "买入卓越企业的最佳时机，往往是在它暂时遭遇麻烦时。", en: "Best time to buy great companies is during temporary troubles.", src: "怎样选择成长股", year: 1958, tags: ["c", "v"] },
  { cn: "持有杰出公司的股票，几乎从不需要卖出。", en: "Selling great companies is rarely necessary.", src: "怎样选择成长股", year: 1958, tags: ["l", "b"] },
  { cn: "了解一家企业，比了解整个行业更重要。", en: "Knowing one company well beats knowing the industry shallowly.", src: "怎样选择成长股", year: 1958, tags: ["cc", "b"] },
  { cn: "只投你愿意花十年时间研究的公司。", en: "Only invest in companies you'd study for ten years.", src: "怎样选择成长股", year: 1958, tags: ["lr", "l"] },
  { cn: "市场短期是非理性的，长期是理性的。", en: "Markets are short-term irrational, long-term rational.", src: "怎样选择成长股", year: 1958, tags: ["m", "l"] },
  { cn: "管理层和员工之间的关系，常常预示着企业的未来。", en: "Labor relations foretell a company's future.", src: "怎样选择成长股", year: 1958, tags: ["b"] },
  { cn: "不要因为短期波动而抛售你坚信的公司。", en: "Don't sell conviction holdings on short-term noise.", src: "怎样选择成长股", year: 1958, tags: ["md", "l"] },
  { cn: "好公司的核心是不断创造价值的能力。", en: "Great companies create value relentlessly.", src: "怎样选择成长股", year: 1958, tags: ["b"] },
  { cn: "一家公司是否值得投资，要看它五年、十年后的样子。", en: "Look at where a company will be in five to ten years.", src: "保守型投资者夜夜安寝", year: 1975, tags: ["l", "b"] },
  { cn: "投资成功的最大秘诀是耐心和勤奋。", en: "Patience and diligence are the secrets.", src: "怎样选择成长股", year: 1958, tags: ["md", "lr"] },
  { cn: "把功课做透，就敢于重仓。", en: "Deep research justifies concentration.", src: "怎样选择成长股", year: 1958, tags: ["cc"] },
  { cn: "频繁的换手只会增加错误的概率。", en: "High turnover increases mistakes.", src: "怎样选择成长股", year: 1958, tags: ["md", "l"] },
  { cn: "好的销售组织是企业护城河的重要部分。", en: "Sales organization is part of the moat.", src: "怎样选择成长股", year: 1958, tags: ["b"] },
  { cn: "对一家公司了解得太少很危险，自以为了解很多更危险。", en: "Knowing too little is dangerous; thinking you know more is worse.", src: "怎样选择成长股", year: 1958, tags: ["cc", "b"] },
  { cn: "好公司能在不增加资本的情况下增加利润。", en: "Great companies grow profits without proportional capital.", src: "怎样选择成长股", year: 1958, tags: ["b", "v"] },
  { cn: "管理层是否对小股东诚实，决定了你是否值得投资。", en: "Honesty toward minority shareholders matters.", src: "保守型投资者夜夜安寝", year: 1975, tags: ["b"] },
  { cn: "不要被高市盈率吓走真正的成长股。", en: "Don't let high P/E scare you off real growth.", src: "怎样选择成长股", year: 1958, tags: ["v", "b"] },
  { cn: "股票投资是一门关于未来的艺术。", en: "Investing is the art of the future.", src: "怎样选择成长股", year: 1958, tags: ["b", "lr"] },
  { cn: "卖出一家伟大公司的唯一理由，是它的基本面发生了根本变化。", en: "Sell only when fundamentals fundamentally change.", src: "怎样选择成长股", year: 1958, tags: ["b", "l"] },
  { cn: "投资者要避免的最大陷阱是『多元化的平庸』。", en: "Avoid the trap of mediocre diversification.", src: "怎样选择成长股", year: 1958, tags: ["cc"] },
  { cn: "成长股的真正价值，是其复利能力。", en: "The true value of a growth stock is its compounding power.", src: "怎样选择成长股", year: 1958, tags: ["l", "b"] },
  { cn: "好公司常常因为短期问题被市场抛售，那是机会。", en: "Short-term troubles in great companies create opportunity.", src: "怎样选择成长股", year: 1958, tags: ["c", "v"] },
  { cn: "不要把大量精力花在小公司上——除非你能彻底搞懂它。", en: "Avoid small companies unless you fully understand them.", src: "怎样选择成长股", year: 1958, tags: ["cc", "r"] },
  { cn: "你买的不是股票，而是公司未来的盈利能力。", en: "You're buying future earnings power, not stock.", src: "怎样选择成长股", year: 1958, tags: ["b", "v"] },
  { cn: "经验告诉我：买对，然后坐稳。", en: "Buy right and sit tight.", src: "怎样选择成长股", year: 1958, tags: ["l", "md"] },
  { cn: "做投资的真正回报来自于你最早期的判断。", en: "The real return comes from your earliest judgment.", src: "怎样选择成长股", year: 1958, tags: ["lr", "b"] },
];

// ========== 利弗莫尔: 30 条 ==========
data["m-livermore"] = [
  { cn: "市场永远是对的，错的只可能是你。", en: "The market is never wrong; opinions often are.", src: "股票大作手回忆录", year: 1923, tags: ["m", "md"] },
  { cn: "投机者最大的敌人是他内心的恐惧、贪婪、希望和傲慢。", en: "Speculator's worst enemies are fear, greed, hope and pride.", src: "股票大作手回忆录", year: 1923, tags: ["md"] },
  { cn: "顺势而为，是华尔街唯一的真理。", en: "The trend is your friend.", src: "股票大作手回忆录", year: 1923, tags: ["m"] },
  { cn: "学会等待——大钱不在频繁交易里。", en: "It was never my thinking that made the big money for me, it was my sitting.", src: "股票大作手回忆录", year: 1923, tags: ["md", "l"] },
  { cn: "永远不要平均下注亏损头寸。", en: "Never average down on a losing trade.", src: "股票大作手回忆录", year: 1923, tags: ["r"] },
  { cn: "在市场顶部，乐观最盛；在底部，恐惧最深。", en: "Optimism peaks at tops; fear peaks at bottoms.", src: "股票大作手回忆录", year: 1923, tags: ["m", "c"] },
  { cn: "如果一笔交易没有按预期发展，立即了结。", en: "Cut losses quickly when a trade doesn't work.", src: "股票大作手回忆录", year: 1923, tags: ["r"] },
  { cn: "投机不是赌博，是对人性的研究。", en: "Speculation is the study of human nature.", src: "股票大作手回忆录", year: 1923, tags: ["m", "md"] },
  { cn: "不要试图捕捉每一波——抓住主要趋势就够了。", en: "Don't try to catch every wave; catch the major trend.", src: "股票大作手回忆录", year: 1923, tags: ["m", "md"] },
  { cn: "在投机中，时机比方向更重要。", en: "Timing matters more than direction.", src: "股票大作手回忆录", year: 1923, tags: ["m"] },
  { cn: "不要轻信他人的建议，自己的判断才是最可靠的。", en: "Trust your own judgment.", src: "股票大作手回忆录", year: 1923, tags: ["md", "lr"] },
  { cn: "投机者必须学会与孤独为伴。", en: "A speculator must learn to be alone.", src: "股票大作手回忆录", year: 1923, tags: ["md", "p"] },
  { cn: "市场永远不会因为你的需要而上涨或下跌。", en: "The market doesn't care about your needs.", src: "股票大作手回忆录", year: 1923, tags: ["m"] },
  { cn: "在错误的位置加仓，是通往破产的捷径。", en: "Adding to a loser is the road to ruin.", src: "股票大作手回忆录", year: 1923, tags: ["r"] },
  { cn: "学会承认错误，是交易者最重要的素质。", en: "Admitting mistakes is the trader's key virtue.", src: "股票大作手回忆录", year: 1923, tags: ["md"] },
  { cn: "市场不会奖励你过去的胜利，只奖励今天的纪律。", en: "Markets reward today's discipline, not yesterday's wins.", src: "股票大作手回忆录", year: 1923, tags: ["md"] },
  { cn: "投机的本质是预判而不是反应。", en: "Speculation is anticipation, not reaction.", src: "股票大作手回忆录", year: 1923, tags: ["m", "md"] },
  { cn: "永远不要为了『扳本』而交易。", en: "Never trade to get even.", src: "股票大作手回忆录", year: 1923, tags: ["md", "r"] },
  { cn: "市场的『不动』本身就是一种信号。", en: "Inactivity is itself a signal.", src: "股票大作手回忆录", year: 1923, tags: ["m"] },
  { cn: "做空需要的是逻辑，而不是情绪。", en: "Shorting requires logic, not emotion.", src: "股票大作手回忆录", year: 1923, tags: ["c", "md"] },
  { cn: "在不确定的时候，最好的位置是空仓。", en: "When in doubt, stay out.", src: "股票大作手回忆录", year: 1923, tags: ["r", "md"] },
  { cn: "市场的真正趋势，是从一片悲观中诞生的。", en: "Real trends are born in pessimism.", src: "股票大作手回忆录", year: 1923, tags: ["c", "m"] },
  { cn: "最大的利润来自于对主要趋势的耐心持有。", en: "Big profits come from holding the main trend.", src: "股票大作手回忆录", year: 1923, tags: ["l", "m"] },
  { cn: "投机者要学会在亏损时迅速行动，在盈利时缓慢行动。", en: "Act fast on losses, slow on gains.", src: "股票大作手回忆录", year: 1923, tags: ["r", "md"] },
  { cn: "永远不要在市场关闭时为自己的预测兴奋。", en: "Don't celebrate forecasts before they pay.", src: "股票大作手回忆录", year: 1923, tags: ["md"] },
  { cn: "成功的投机者必须自律到近乎冷酷。", en: "A successful speculator is almost ruthlessly disciplined.", src: "股票大作手回忆录", year: 1923, tags: ["md"] },
  { cn: "市场的每一次极端，都是另一次极端的种子。", en: "Every extreme contains the seed of its opposite.", src: "股票大作手回忆录", year: 1923, tags: ["m", "c"] },
  { cn: "不要恋战——头寸应当为机会服务。", en: "Don't fall in love with positions.", src: "股票大作手回忆录", year: 1923, tags: ["md", "r"] },
  { cn: "我从未因为耐心而亏过钱。", en: "I never lost money by being patient.", src: "股票大作手回忆录", year: 1923, tags: ["md", "l"] },
  { cn: "市场的真理藏在价格行为之中，而不是新闻里。", en: "Truth lies in price action, not headlines.", src: "股票大作手回忆录", year: 1923, tags: ["m"] },
];

// ========== 塔勒布: 30 条 ==========
data["m-taleb"] = [
  { cn: "脆弱者害怕波动，反脆弱者从波动中获益。", en: "Fragile fears volatility; antifragile gains from it.", src: "反脆弱", year: 2012, tags: ["r", "p"] },
  { cn: "永远不要为了短期收益承担可能毁灭你的风险。", en: "Never risk ruin for marginal gain.", src: "黑天鹅", year: 2007, tags: ["r"] },
  { cn: "概率小但影响大的事件，决定了一切。", en: "Rare events with huge impact dominate outcomes.", src: "黑天鹅", year: 2007, tags: ["r", "m"] },
  { cn: "经验告诉我：千次正确不抵一次毁灭。", en: "A thousand wins do not outweigh one ruin.", src: "反脆弱", year: 2012, tags: ["r"] },
  { cn: "不要被精确数字欺骗，模糊但正确胜过精确但错误。", en: "Better to be approximately right than precisely wrong.", src: "黑天鹅", year: 2007, tags: ["md"] },
  { cn: "你不能用平均数来理解尾部风险。", en: "Averages hide tail risk.", src: "黑天鹅", year: 2007, tags: ["r", "m"] },
  { cn: "只有能承受冲击的系统才值得信任。", en: "Trust systems that survive shocks.", src: "反脆弱", year: 2012, tags: ["r"] },
  { cn: "把不可逆的损失放在第一位。", en: "Avoid irreversible losses first.", src: "反脆弱", year: 2012, tags: ["r"] },
  { cn: "复杂的预测往往是傲慢的伪装。", en: "Complex forecasts disguise arrogance.", src: "黑天鹅", year: 2007, tags: ["m", "md"] },
  { cn: "如果你不暴露在尾部风险中，你的回报永远是平庸的。", en: "Without exposure to tails, returns stay mediocre.", src: "反脆弱", year: 2012, tags: ["r", "v"] },
  { cn: "时间是抗脆弱性的最好检验者。", en: "Time tests antifragility best.", src: "反脆弱", year: 2012, tags: ["l", "r"] },
  { cn: "稳定的系统往往最脆弱，混乱的系统反而更强健。", en: "Stable-looking systems are often most fragile.", src: "反脆弱", year: 2012, tags: ["r", "m"] },
  { cn: "我们更应该担忧的是看起来安全的事物。", en: "Worry about what looks safe.", src: "反脆弱", year: 2012, tags: ["r", "c"] },
  { cn: "把你不能承受的损失从你的人生中移走。", en: "Remove what you can't survive.", src: "反脆弱", year: 2012, tags: ["r"] },
  { cn: "不要追求精准的预测，追求强健的应对。", en: "Don't seek precision; seek robustness.", src: "黑天鹅", year: 2007, tags: ["md", "r"] },
  { cn: "市场的尾部里藏着所有真正的故事。", en: "All real stories live in the tails.", src: "黑天鹅", year: 2007, tags: ["m"] },
  { cn: "聪明的人会让自己暴露在好的不确定性中。", en: "Wise people expose themselves to good uncertainty.", src: "反脆弱", year: 2012, tags: ["r", "lr"] },
  { cn: "幸存才是真正的胜利。", en: "Survival is the only victory.", src: "反脆弱", year: 2012, tags: ["r", "p"] },
  { cn: "不要相信那些没有皮肉之痛的专家。", en: "Don't trust experts without skin in the game.", src: "Skin in the Game", year: 2018, tags: ["p", "lr"] },
  { cn: "理论与实践之间的鸿沟，往往就是亏损的根源。", en: "The gap between theory and practice is where losses live.", src: "Skin in the Game", year: 2018, tags: ["r", "lr"] },
  { cn: "经验比理论更值得信赖。", en: "Experience trumps theory.", src: "反脆弱", year: 2012, tags: ["lr"] },
  { cn: "对极端事件的过度自信，是金融最常见的死法。", en: "Overconfidence in tails is finance's most common death.", src: "黑天鹅", year: 2007, tags: ["r", "md"] },
  { cn: "不要把负相关性当作消失的风险。", en: "Negative correlation is not the absence of risk.", src: "黑天鹅", year: 2007, tags: ["r"] },
  { cn: "时间会暴露所有伪装的脆弱性。", en: "Time exposes hidden fragility.", src: "反脆弱", year: 2012, tags: ["l", "r"] },
  { cn: "做事的最好方式，是给自己留下足够多的可选项。", en: "Optionality is the secret of success.", src: "反脆弱", year: 2012, tags: ["r", "md"] },
  { cn: "选项越多，反脆弱性越强。", en: "More options, more antifragility.", src: "反脆弱", year: 2012, tags: ["r"] },
  { cn: "不要相信那种用复杂术语保护自己声誉的预测。", en: "Distrust forecasts hiding behind jargon.", src: "黑天鹅", year: 2007, tags: ["md", "lr"] },
  { cn: "对极端不确定性的最好回应是保守。", en: "Conservatism is the best answer to extreme uncertainty.", src: "黑天鹅", year: 2007, tags: ["r", "md"] },
  { cn: "在市场上，幸存者偏差让你看到的成功都是表面。", en: "Survivor bias hides the truth of success.", src: "随机漫步的傻瓜", year: 2001, tags: ["lr", "md"] },
  { cn: "你看到的所有『方法论』，都被幸存者偏差污染了。", en: "Every methodology you see is contaminated by survivor bias.", src: "随机漫步的傻瓜", year: 2001, tags: ["lr", "c"] },
];

// ========== 卡拉曼: 30 条 ==========
data["m-klarman"] = [
  { cn: "价值投资的精髓是逆向思维加上严格的纪律。", en: "Value investing is contrarian thinking plus discipline.", src: "安全边际", year: 1991, tags: ["v", "c", "md"] },
  { cn: "等待是价值投资者最重要的武器。", en: "Patience is the value investor's greatest weapon.", src: "安全边际", year: 1991, tags: ["md", "l"] },
  { cn: "在大多数人不愿意持有的资产中，往往蕴含最大的价值。", en: "Greatest value lives where others won't go.", src: "安全边际", year: 1991, tags: ["c", "v"] },
  { cn: "牢记：风险不等于波动，风险是永久亏损本金。", en: "Risk is permanent loss, not volatility.", src: "安全边际", year: 1991, tags: ["r"] },
  { cn: "卓越的回报来自于在被市场厌恶时买入。", en: "Outperformance comes from buying when others sell.", src: "安全边际", year: 1991, tags: ["c"] },
  { cn: "投资中没有便宜货，就保持耐心，不要勉强出手。", en: "If there's no bargain, sit on cash.", src: "安全边际", year: 1991, tags: ["md", "v"] },
  { cn: "我们不预测市场，我们只为最坏情况做准备。", en: "We don't predict; we prepare for the worst.", src: "Baupost 致投资人信", tags: ["r"] },
  { cn: "投资是一项需要耐心、纪律与逆向勇气的事业。", en: "Investing requires patience, discipline, and contrarian courage.", src: "安全边际", year: 1991, tags: ["md", "c"] },
  { cn: "好的投资者从不依赖市场上涨来盈利。", en: "Good investors don't rely on rising markets.", src: "安全边际", year: 1991, tags: ["r", "md"] },
  { cn: "不要因为市场涨得快就放弃安全边际。", en: "Don't abandon margin of safety in rising markets.", src: "安全边际", year: 1991, tags: ["v", "r"] },
  { cn: "投资的圣杯是『可以承受错误的策略』。", en: "The holy grail is a strategy that can survive being wrong.", src: "安全边际", year: 1991, tags: ["r", "md"] },
  { cn: "市场的不理性常常持续比你预期的更久。", en: "Markets stay irrational longer than you expect.", src: "安全边际", year: 1991, tags: ["m", "r"] },
  { cn: "我们的目标是少亏，而不是多赚。", en: "Our goal is to lose less, not gain more.", src: "Baupost 致投资人信", tags: ["r"] },
  { cn: "卓越的投资者懂得在大多数时候什么也不做。", en: "Great investors do nothing most of the time.", src: "安全边际", year: 1991, tags: ["md", "l"] },
  { cn: "现金不是负担，是机会的『弹药』。", en: "Cash is not a drag; it's optionality.", src: "Baupost 致投资人信", tags: ["r", "md"] },
  { cn: "最好的投资机会，往往出现在最让人不舒服的时候。", en: "Best opportunities arise in the most uncomfortable moments.", src: "安全边际", year: 1991, tags: ["c"] },
  { cn: "不要因为别人都在赚钱就改变你的纪律。", en: "Don't abandon discipline because others are profiting.", src: "安全边际", year: 1991, tags: ["md", "c"] },
  { cn: "估值的核心，是承认未来不可知。", en: "Valuation acknowledges the unknowable future.", src: "安全边际", year: 1991, tags: ["v", "r"] },
  { cn: "我们追求绝对回报，而不是相对回报。", en: "We pursue absolute, not relative returns.", src: "Baupost 致投资人信", tags: ["v"] },
  { cn: "好的投资过程比好的短期结果更重要。", en: "Process trumps short-term outcome.", src: "安全边际", year: 1991, tags: ["md", "lr"] },
  { cn: "在市场上没有英雄，只有幸存者。", en: "Markets have no heroes, only survivors.", src: "安全边际", year: 1991, tags: ["r"] },
  { cn: "那些声称『这次不一样』的投资者，往往是亏得最惨的。", en: "'This time is different' is the costliest sentence in finance.", src: "安全边际", year: 1991, tags: ["c", "lr"] },
  { cn: "投资中最大的优势是结构性的耐心。", en: "Structural patience is the biggest edge.", src: "Baupost 致投资人信", tags: ["md", "l"] },
  { cn: "我宁愿错过机会，也不要承担灾难性风险。", en: "Better to miss opportunity than face ruin.", src: "安全边际", year: 1991, tags: ["r", "md"] },
  { cn: "永远不要让别人的情绪决定你的仓位。", en: "Don't let others' emotions size your positions.", src: "安全边际", year: 1991, tags: ["md", "c"] },
  { cn: "在市场最热闹时，做最安静的事。", en: "Be quietest when the market is loudest.", src: "Baupost 致投资人信", tags: ["c", "md"] },
  { cn: "投资的真正风险是认知风险。", en: "The real risk in investing is cognitive risk.", src: "安全边际", year: 1991, tags: ["cc", "lr"] },
  { cn: "投资是一项严肃的事业——把它当作事业来对待。", en: "Treat investing as a serious profession.", src: "安全边际", year: 1991, tags: ["md", "lr"] },
  { cn: "我们建立的不是高回报组合，而是能在风暴中生存的组合。", en: "We build portfolios that survive storms.", src: "Baupost 致投资人信", tags: ["r"] },
  { cn: "买入是行动，等待是艺术。", en: "Buying is action; waiting is art.", src: "安全边际", year: 1991, tags: ["md", "l"] },
];

module.exports = data;
